UPDATE room_participants
SET white_user_id = #{whiteUserId}, white_token = #{whiteToken}
WHERE room_id = #{roomId}
  AND white_user_id IS NULL

UPDATE room_participants
SET black_user_id = #{blackUserId},
    black_token = #{blackToken},
    white_user_id = #{whiteUserId},
    white_token = #{whiteToken}
WHERE room_id = #{roomId}

UPDATE room_participants
SET white_is_bot = #{whiteIsBot},
    bot_search_depth_min = #{dmin},
    bot_search_depth_max = #{dmax}
WHERE room_id = #{roomId}
